var isSubstringPresent = function(s) {
    const pairs = new Set();
    for (let i = 0; i < s.length - 1; i++) pairs.add(s[i] + s[i+1]);
    const rev = s.split('').reverse().join('');
    for (let i = 0; i < rev.length - 1; i++) {
        if (pairs.has(rev[i] + rev[i+1])) return true;
    }
    return false;
};
